@app.route('/login', methods=['POST'])
def login():
    """Handle user authentication and generate authorization code."""
    content_type = request.content_type or ''
    if 'application/json' in content_type:
        data = request.get_json(silent=True) or {}
        username = _sanitize_input(data.get('username'))
        password = data.get('password', '')
    else:
        username = _sanitize_input(request.form.get('username'))
        password = request.form.get('password', '')

    if not username or not password:
        return jsonify({'error': 'invalid_request', 'error_description': 'Missing credentials'}), 400

    # Verify credentials
