@app.route('/revoke', methods=['POST'])
def revoke():
    """Token revocation endpoint."""
    content_type = request.content_type or ''

    if 'application/json' in content_type:
        data = request.get_json(silent=True) or {}
    else:
        data = request.form.to_dict()

    token = data.get('token', '')
    client_id = _sanitize_input(data.get('client_id'))
    client_secret = data.get('client_secret', '')

    if not token or not client_id or not client_secret:
        return jsonify({'error': 'invalid_request'}), 400

    # Authenticate client
    if not _verify_client_secret(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401

    token_hash = _hash_token(token)

    if token_hash in access_tokens:
        token_data = access_tokens[token_hash]
        # Verify the token belongs to this client
        if token_data['client_id'] == client_id:
            del access_tokens[token_hash]
            logger.info("Token revoked for client %s", client_id)

    # Always return 200 per RFC 7009
    return jsonify({'status': 'ok'}), 200


@app.route('/userinfo', methods=['GET'])
@require_auth
def userinfo():
    """Protected resource endpoint - returns user info."""
    token_data = request.token_data

    # Check scope
    scopes = set(token_data.get('scope', '').split())
    if 'profile' not in scopes and 'read' not in scopes:
        return jsonify({'error': 'insufficient_scope'}), 403

    return jsonify({
        'user_id': token_data['user_id'],
        'scope': token_data['scope']
    }), 200


@app.route('/introspect', methods=['POST'])
def introspect():
    """Token introspection endpoint (RFC 7662)."""
    content_type = request.content_type or ''

    if 'application/json' in content_type:
        data = request.get_json(silent=True) or {}
    else:
        data = request.form.to_dict()

    token = data.get('token', '')
    client_id = _sanitize_input(data.get('client_id'))
    client_secret = data.get('client_secret', '')

    if not client_id or not client_secret:
        return jsonify({'error': 'invalid_client'}), 401

    # Authenticate client
    if not _verify_client_secret(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401

    if not token:
        return jsonify({'active': False}), 200

    token_hash = _hash_token(token)

    if token_hash not in access_tokens:
        return jsonify({'active': False}), 200

    token_data = access_tokens[token_hash]

    if time.time() > token_data['expires_at']:
        del access_tokens[token_hash]
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'scope': token_data['scope'],
        'client_id': token_data['client_id'],
        'username': token_data['user_id'],
        'exp': int(token_data['expires_at']),
        'iat': int(token_data['created_at'])
    }), 200


