# --- Client Registration Helper (for setup) ---
def register_client(client_id, client_secret, redirect_uris):
    """Register a new OAuth client programmatically."""
    if not client_id or not client_secret or not redirect_uris:
        raise ValueError("All parameters are required")

    # Validate redirect URIs
    for uri in redirect_uris:
        parsed = urlparse(uri)
        if not parsed.scheme or not parsed.netloc:
            raise ValueError(f"Invalid redirect URI: {uri}")

    registered_clients[client_id] = {
        'secret_hash': hashlib.sha256(client_secret.encode('utf-8')).hexdigest()
    }
    allowed_redirect_uris[client_id] = list(redirect_uris)
    logger.info("Registered new OAuth client: %s", client_id)


def register_user(username, password):
    """Register a new user programmatically."""
    if not username or not password:
        raise ValueError("Username and password are required")

    salt = os.urandom(32)
    password_hash = hashlib.pbkdf2_hmac(
        'sha256', password.encode('utf-8'), salt, 100000
    )
    users[username] = {'password_hash': password_hash, 'salt': salt}
    logger.info("Registered new user: %s", username)


